    downstream_services: downstreamServices,
    error: req.telemetry.error
  };

  if (statusCode >= 500) {
    req.log.error(payload, "Request completed with failure");
  } else if (statusCode >= 400) {
    req.log.warn(payload, "Request completed with client error");
  } else {
    req.log.info(payload, "Request completed successfully");
  }
});

